public class BankAccount {
    // Static field to count total accounts
    static int totalAccounts = 0;

    // Instance fields
    String owner;
    double balance;

    // Constructor: accepts owner and balance, increments totalAccounts

    // displayInfo(): prints owner, balance, and totalAccounts

    public static void main(String[] args) {
        BankAccount a1 = new BankAccount("Alice", 1000.0);
        BankAccount a2 = new BankAccount("Bob", 500.0);
        BankAccount a3 = new BankAccount("Carol", 750.0);

        a1.displayInfo();
        a2.displayInfo();
        a3.displayInfo();
    }
}

public class MathUtils {

    // Static method: max(int a, int b, int c) — returns the largest

    // Static method: isEven(int n) — returns true if n is even

    public static void main(String[] args) {
        System.out.println("Max of 12, 7, 19: " + MathUtils.max(12, 7, 19));
        System.out.println("Max of 5, 5, 3: " + MathUtils.max(5, 5, 3));
        System.out.println("Is 8 even? " + MathUtils.isEven(8));
        System.out.println("Is 13 even? " + MathUtils.isEven(13));
    }
}

public class Rectangle {
    double width;
    double height;

    // Constructor

    // Instance method: getArea() — returns width * height

    // Static factory method: square(double side) — returns a new Rectangle where width == height == side

    public static void main(String[] args) {
        Rectangle r = new Rectangle(4.0, 6.0);
        System.out.println("Rectangle area: " + r.getArea());

        Rectangle sq = Rectangle.square(5.0);
        System.out.println("Square area: " + sq.getArea());
    }
}
